package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"net/http"
)

// User represents a user in the database
type User struct {
	ID   int    `json:"id"`
	Name string `json:"name"`
}

func main() {
	// Connect to the PostgreSQL database
	db, err := sql.Open("postgres", "postgresql://user:password@host:port/database?sslmode=disable")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer db.Close()

	// Set up the HTTP handler
	http.HandleFunc("/search", func(w http.ResponseWriter, r *http.Request) {
		// Get the username from the query parameter
		username := r.URL.Query().Get("username")

		// Query the database for users with the given username
		rows, err := db.Query("SELECT id, name FROM users WHERE username = $1", username)
		if err != nil {
			fmt.Println(err)
			http.Error(w, http.StatusText(500), 500)
			return
		}
		defer rows.Close()

		// Create a slice of Users to store the results
		var users []User

		// Loop through the rows and create a User object for each one
		for rows.Next() {
			var user User
			if err := rows.Scan(&user.ID, &user.Name); err != nil {
				fmt.Println(err)
				continue
			}
			users = append(users, user)
		}

		// Return the results as JSON
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(users)
	})

	// Start the HTTP server
	http.ListenAndServe(":8080", nil)
}